const vocabRows = $('Load Vocabulary from Sheets').all();

const aliasMap = {};
const bannedSet = new Set();
const requiredTags = [];

for (const row of vocabRows) {
  const r = (row && row.json) || {};
  const type = String(r.rule_type || '').trim().toLowerCase();
  const tag = String(r.tag || '').trim().toLowerCase();
  if (!tag) continue;
  if (type === 'alias') {
    const canonical = String(r.canonical || '').trim().toLowerCase();
    if (canonical) aliasMap[tag] = canonical;
  } else if (type === 'banned') {
    bannedSet.add(tag);
  } else if (type === 'required') {
    requiredTags.push(tag);
  }
}

const MAX_TAG_CHARS = 500;
const results = [];

for (const item of $input.all()) {
  const snippet = (item.json && item.json.snippet) || {};
  const originalTags = Array.isArray(snippet.tags) ? snippet.tags : [];

  let working = originalTags
    .map(t => String(t).toLowerCase().replace(/,/g, ' ').trim().split(' ').filter(Boolean).join(' '))
    .filter(t => t.length > 0);

  working = working.map(t => aliasMap[t] || t);
  working = working.filter(t => !bannedSet.has(t));

  const seen = new Set();
  const deduped = [];
  for (const t of working) {
    if (!seen.has(t)) { seen.add(t); deduped.push(t); }
  }
  for (const req of requiredTags) {
    if (!seen.has(req)) { seen.add(req); deduped.push(req); }
  }

  const finalTags = [];
  let used = 0;
  let truncated = false;
  for (const t of deduped) {
    const cost = t.length + (t.indexOf(' ') >= 0 ? 2 : 0);
    const sep = finalTags.length > 0 ? 1 : 0;
    if (used + sep + cost > MAX_TAG_CHARS) { truncated = true; break; }
    finalTags.push(t);
    used += sep + cost;
  }

  const currentSet = new Set(originalTags);
  const nextSet = new Set(finalTags);
  let changed = currentSet.size !== nextSet.size;
  if (!changed) {
    for (const t of nextSet) {
      if (!currentSet.has(t)) { changed = true; break; }
    }
  }

  results.push({
    json: {
      videoId: item.json.id,
      title: snippet.title || '',
      categoryId: snippet.categoryId || '',
      originalTags: originalTags,
      normalizedTags: finalTags,
      normalizedTagsString: finalTags.join(','),
      tagCharCount: used,
      truncated: truncated,
      changed: changed
    }
  });
}

return results;
